const notes = [
  { title: "Map Function", description: "Loops through the array." },
  {
    title: "Reduce Function",
    description:
      "Accumulate a value by doing something to each item of the array.",
  },
  {
    title: "Filter Function",
    description:
      "Loops through the array and returns only if the given condition is met.",
  },
];

export default notes;
